+          tag: 'node-offline', // Prevents duplicate notifications
+          requireInteraction: true, // Keeps notification until dismissed
+        })
+      }
+    }
+    prevOfflineCountRef.current = offlineCount
+  }, [offlineCount, offlineNodes])
