+    // This forces the system to open in default browser
+    const link = document.createElement('a')
+    link.href = fullUrl
+    link.target = '_blank'
+    link.rel = 'noopener noreferrer'
+    document.body.appendChild(link)
+    link.click()
+    document.body.removeChild(link)
+  }, [])
